
INSERT INTO public.opportunities (title, category, description, revenue_estimate, downloads, market_size, growth_percent, competition_score, opportunity_score, growth_velocity, is_hidden_gem, tags) VALUES

-- ── Health & Fitness Apps ──
('Hormone Tracking App for Women', 'Mobile Apps', 'Tracks cycle, mood, energy, and symptoms with AI pattern recognition and personalized insights. Clue has 11M users but lacks AI coaching; 800M women of reproductive age globally underserved.', '$5k–$30k MRR', '5M+/mo', '$4.2B', 82, 46, 90, 'Explosive', true, ARRAY['mobile','health','womens-health','tracking']),
('AI Personal Trainer App', 'Mobile Apps', 'Camera-based form correction, adaptive workout generation, and recovery coaching with no gym required. Peloton app $13/mo; AI coach generates unlimited custom workouts for same price with visual feedback.', '$5k–$30k MRR', '3M+/mo', '$4.8B', 80, 52, 88, 'Rising', false, ARRAY['mobile','fitness','AI','personal-trainer']),
('Walking & Steps Gamification App', 'Mobile Apps', 'Turns daily steps into narrative adventures, streaks, and community challenges. Pokémon GO proved location + gamification works; health-first walking app serves 55+ demographic gap.', '$3k–$18k MRR', '10M+/mo', '$2.8B', 72, 55, 83, 'Rising', false, ARRAY['mobile','fitness','gamification','walking']),
('Intermittent Fasting Tracker', 'Mobile Apps', 'Smart fasting window tracker with metabolic optimization insights and CGM integration. Zero has 5M downloads; AI-driven metabolic coaching layer missing from all current fasting apps.', '$3k–$18k MRR', '8M+/mo', '$2.5B', 74, 55, 83, 'Rising', false, ARRAY['mobile','fasting','health','tracking']),
('Breathwork & HRV Training App', 'Mobile Apps', 'Guided breathing protocols with Apple Watch / Garmin HRV monitoring and stress scoring. Stress costs US employers $300B/yr; 50M+ smartwatch users have HRV hardware but no dedicated app.', '$3k–$18k MRR', '4M+/mo', '$2.2B', 76, 46, 85, 'Rising', true, ARRAY['mobile','breathwork','HRV','stress']),

-- ── Productivity Apps ──
('AI Daily Planner App', 'Mobile Apps', 'Intelligently schedules tasks, meetings, and deep work blocks by priority and energy level. Todoist has 30M users; AI time-blocking that respects cognitive load is the missing layer.', '$4k–$24k MRR', '5M+/mo', '$3.5B', 80, 52, 88, 'Rising', false, ARRAY['mobile','productivity','AI','planning']),
('Focus & Deep Work Timer App', 'Mobile Apps', 'Combines Pomodoro, ambient sound, website blocking, and AI focus coaching in one mobile app. Forest app 5M downloads; unified focus suite with AI adaptation and progress analytics still needed.', '$3k–$18k MRR', '8M+/mo', '$2.2B', 74, 52, 83, 'Rising', false, ARRAY['mobile','focus','deep-work','productivity']),
('AI Meeting Prep & Follow-Up App', 'Mobile Apps', 'Briefs you before every meeting and auto-drafts follow-up emails from calendar context. Professionals attend 23 hours of meetings/week; prep and follow-up account for 30% of meeting waste.', '$4k–$22k MRR', '2M+/mo', '$3.0B', 78, 44, 87, 'Rising', true, ARRAY['mobile','meetings','AI','productivity']),
('Second Brain Note-Taking App', 'Mobile Apps', 'AI-connected notes that surface relevant past ideas during new note creation and research. Obsidian has 1M+ users but requires manual setup; AI-connected graph for non-technical users is open.', '$4k–$24k MRR', '3M+/mo', '$3.2B', 78, 50, 87, 'Rising', true, ARRAY['mobile','notes','second-brain','AI']),
('Screen Time & Digital Wellbeing App', 'Mobile Apps', 'AI-personalized screen time limits with behavioral nudges, not just hard blocks. Apple Screen Time is blunt; parents and professionals need nuanced AI coaching on device habits.', '$3k–$18k MRR', '6M+/mo', '$2.0B', 76, 48, 85, 'Rising', false, ARRAY['mobile','screen-time','digital-wellness','AI']),

-- ── Finance & Money ──
('Split Bills & Group Expense App', 'Mobile Apps', 'Simplifies group trip, dinner, and roommate expense splitting with AI receipt scanning. Splitwise has 50M users but poor UX; AI receipt scanning + instant Venmo/Zelle integration is the upgrade.', '$3k–$18k MRR', '15M+/mo', '$2.8B', 72, 58, 82, 'Rising', false, ARRAY['mobile','finance','expense-splitting','social']),
('Subscription Management & Cancellation App', 'Mobile Apps', 'Tracks all subscriptions, flags unused ones, and cancels them on user''s behalf in one tap. Average American pays for 4.5 forgotten subscriptions totaling $133/mo; app pays for itself immediately.', '$3k–$18k MRR', '10M+/mo', '$2.5B', 78, 52, 87, 'Rising', true, ARRAY['mobile','subscriptions','finance','savings']),
('AI Grocery Budget & Meal Plan App', 'Mobile Apps', 'Plans meals within a budget, generates a shopping list, and tracks nutritional goals simultaneously. Food inflation drove 200% increase in budget cooking apps; AI nutritionist + budget optimizer is the gap.', '$3k–$18k MRR', '8M+/mo', '$2.5B', 76, 50, 85, 'Rising', true, ARRAY['mobile','grocery','meal-planning','budget']),
('Crypto Portfolio Tracker & Alert App', 'Mobile Apps', 'Real-time portfolio tracking with AI-generated market summaries and customizable price alerts. CoinGecko has 10M users; AI narrative layer explaining why prices moved is the missing feature.', '$4k–$22k MRR', '6M+/mo', '$3.2B', 72, 55, 82, 'Rising', false, ARRAY['mobile','crypto','portfolio','tracking']),

